-- Optimized SQL script to create and populate allowed_wallets table
-- Generated from academy_submissions_rows_cleaned_v2.csv

-- 1. Create whitelist table if not exists
CREATE TABLE IF NOT EXISTS allowed_wallets (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    wallet_address TEXT UNIQUE NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- 2. Enable Row Level Security (RLS)
ALTER TABLE allowed_wallets ENABLE ROW LEVEL SECURITY;

-- 3. Re-create public read access policy if not exists
DROP POLICY IF EXISTS "Allow public read access to allowed_wallets" ON allowed_wallets;
CREATE POLICY "Allow public read access to allowed_wallets" 
ON allowed_wallets 
FOR SELECT 
USING (true);

